            "LOWER(m.denominationCommuneInternationale) LIKE LOWER(CONCAT('%', :keyword, '%')) OR " +
            "LOWER(m.codeCIP) LIKE LOWER(CONCAT('%', :keyword, '%'))")
    List<Medicament> searchMedicaments(@Param("keyword") String keyword);

